import itertools, numpy as np, math, random
def prob_success(w,p):
    m=len(w)
    s=0.0
    for mask in range(1<<m):
        sm=0; k=0
        for i in range(m):
            if mask>>i &1:
                sm+=w[i]; k+=1
        if sm>=p-1e-12:
            s+=p**k*(1-p)**(m-k)
    return s
