import numpy as np, random, math

def scan_measure(w, starts, p, N=10000):
    t=np.linspace(0,1,N,endpoint=False)
    S=np.zeros(N)
    for wi,ui in zip(w,starts):
        # interval [ui, ui+p] modulo; S(t) for window [t,t+p]? Equivalent item at position U_i in [t,t+p] -> t in [U_i-p,U_i]
        a=(ui-p)%1; b=ui%1
        if a<=b:
            mask=(t>=a)&(t<=b) # endpoints negligible
        else:
            mask=(t>=a)|(t<=b)
        S[mask]+=wi
    return np.mean(S>=p), S

